/// <summary>
/// Classe-base de todas as condições de FALHA adicionais de um
/// <see cref="ChallengeDefinition"/> (além do tempo esgotado, que é tratado
/// directamente pelo ChallengeManager via 'hasTimeLimit'/'timeLimitSeconds').
///
/// Para adicionar uma nova condição de falha: cria uma subclasse
/// [System.Serializable] em Data/Objectives/ com prefixo "FailCondition_" e
/// implementa IsFailed() (e, se fizer sentido, ResetState()). Aparece
/// automaticamente no botão "+ Adicionar Condição de Falha" do
/// ChallengeDefinitionEditor (PolymorphicListDrawer, Tarefa #10/#14).
///
/// Exemplos previstos: FailCondition_PlayerDamaged (desafios "sem dano"),
/// FailCondition_NpcDefeated (NPC defendido morreu), FailCondition_Variable
/// (uma variável global bool atingiu o valor de falha).
/// </summary>
[System.Serializable]
public abstract class ChallengeFailCondition
{
    /// <summary>Mensagem opcional mostrada no ecrã "FALHOU" quando esta condição causa a falha (ex: "Foste atingido!"). Vazio = usa a mensagem genérica do desafio.</summary>
    public string failMessage;

    /// <summary>Chamado ao iniciar ou reiniciar o desafio — repõe estado interno.</summary>
    public virtual void ResetState() { }

    /// <summary>Devolve true quando esta condição causa a falha imediata do desafio.</summary>
    public abstract bool IsFailed();
}
